mapper.select:
SELECT ( CASE WHEN T.DEPT_ID = '620000' THEN T.DEPT_ID WHEN T.DEPT_ID LIKE '626%' THEN T.DEPT_ID ELSE rpad(substr(T.DEPT_ID, 1, 4), 6, 0) END ) AS sjdm, count(DISTINCT t.DJXH) AS bs, sum(t.YBTSE) AS ybtse, sum(t.CBJJE) AS cbjje, sum(t.SZGHJE) AS szghje, sum(t.QGGHJE) AS qgghje, sum(t.SZGHJE + t.QGGHJE) AS sjghje, sum(t.SZGHJE + t.QGGHJE + T.CBJJE) AS xjghje FROM gh_jf t
t.JSBJ IN ('Y', 'S', 'W') and t.dept_id = #{query.deptId}
and MID(HKPCH,1,8) between #{query.beginHkpch} and #{query.endHkpch}
and t.JSRQ between #{query.beginJsrq} and #{query.endJsrq}
GROUP BY sjdm
